public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // в”Ђв”Ђ Toy в”Ђв”Ђ
        try {
            Toy woody = new Toy("Woody", "Toy Story", "Andy");
            check("Toy.getName()", "Woody", woody.getName());
        } catch (Exception e) { fail("Toy.getName()", e); }

        try {
            Toy woody = new Toy("Woody", "Toy Story", "Andy");
            check("Toy.getOwner()", "Andy", woody.getOwner());
        } catch (Exception e) { fail("Toy.getOwner()", e); }

        try {
            Toy woody = new Toy("Woody", "Toy Story", "Andy");
            check("Toy.perform()",
                  "Woody comes to life and plays!", woody.perform());
        } catch (Exception e) { fail("Toy.perform()", e); }

        try {
            Toy buzz = new Toy("Buzz", "Toy Story", "Andy");
            check("Toy.getPlayed()",
                  "Buzz is being played with by Andy!", buzz.getPlayed());
        } catch (Exception e) { fail("Toy.getPlayed()", e); }

        try {
            Toy woody = new Toy("Woody", "Toy Story", "Andy");
            check("Toy.toString()",
                  "Toy: Woody (Toy Story) вЂ” Owner: Andy", woody.toString());
        } catch (Exception e) { fail("Toy.toString()", e); }

        // в”Ђв”Ђ Monster в”Ђв”Ђ
        try {
            Monster sulley = new Monster("Sulley", "Monsters Inc", 10);
            check("Monster.getName()", "Sulley", sulley.getName());
        } catch (Exception e) { fail("Monster.getName()", e); }

        try {
            Monster sulley = new Monster("Sulley", "Monsters Inc", 10);
            check("Monster.getScarePower()", "10",
                  String.valueOf(sulley.getScarePower()));
        } catch (Exception e) { fail("Monster.getScarePower()", e); }

        try {
            Monster sulley = new Monster("Sulley", "Monsters Inc", 10);
            check("Monster.perform()",
                  "Sulley leaps out and roars!", sulley.perform());
        } catch (Exception e) { fail("Monster.perform()", e); }

        try {
            Monster mike = new Monster("Mike", "Monsters Inc", 6);
            check("Monster.scare()",
                  "Mike scares with power 6!", mike.scare());
        } catch (Exception e) { fail("Monster.scare()", e); }

        try {
            Monster sulley = new Monster("Sulley", "Monsters Inc", 10);
            check("Monster.toString()",
                  "Monster: Sulley (Monsters Inc) вЂ” Scare: 10",
                  sulley.toString());
        } catch (Exception e) { fail("Monster.toString()", e); }

        // в”Ђв”Ђ SuperPixar в”Ђв”Ђ
        try {
            SuperPixar mr = new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength");
            check("SuperPixar.getName()", "Mr. Incredible", mr.getName());
        } catch (Exception e) { fail("SuperPixar.getName()", e); }

        try {
            SuperPixar mr = new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength");
            check("SuperPixar.getPower()", "Super strength", mr.getPower());
        } catch (Exception e) { fail("SuperPixar.getPower()", e); }

        try {
            SuperPixar mr = new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength");
            check("SuperPixar.perform()",
                  "Mr. Incredible strikes a heroic pose!", mr.perform());
        } catch (Exception e) { fail("SuperPixar.perform()", e); }

        try {
            SuperPixar el = new SuperPixar("Elastigirl", "The Incredibles", "Elasticity");
            check("SuperPixar.save()",
                  "Elastigirl saves the day with Elasticity!", el.save());
        } catch (Exception e) { fail("SuperPixar.save()", e); }

        try {
            SuperPixar mr = new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength");
            check("SuperPixar.toString()",
                  "Super: Mr. Incredible (The Incredibles) вЂ” Power: Super strength",
                  mr.toString());
        } catch (Exception e) { fail("SuperPixar.toString()", e); }

        // в”Ђв”Ђ Polymorphism: perform() through base type в”Ђв”Ђ
        try {
            PixarCharacter p = new Toy("Woody", "Toy Story", "Andy");
            check("Polymorphic perform() on Toy",
                  "Woody comes to life and plays!", p.perform());
        } catch (Exception e) { fail("Polymorphic perform() on Toy", e); }

        try {
            PixarCharacter p = new Monster("Sulley", "Monsters Inc", 10);
            check("Polymorphic perform() on Monster",
                  "Sulley leaps out and roars!", p.perform());
        } catch (Exception e) { fail("Polymorphic perform() on Monster", e); }

        // в”Ђв”Ђ Polymorphism: toString() through base type в”Ђв”Ђ
        try {
            PixarCharacter p = new SuperPixar("Dash", "The Incredibles", "Super speed");
            check("Polymorphic toString() on SuperPixar",
                  "Super: Dash (The Incredibles) вЂ” Power: Super speed",
                  p.toString());
        } catch (Exception e) { fail("Polymorphic toString() on SuperPixar", e); }

        // в”Ђв”Ђ instanceof checks в”Ђв”Ђ
        try {
            PixarCharacter p = new Toy("Rex", "Toy Story", "Andy");
            boolean ok = (p instanceof Toy) && (p instanceof PixarCharacter)
                         && !(p instanceof Monster);
            check("instanceof: Toy is Toy & PixarCharacter, not Monster",
                  "true", String.valueOf(ok));
        } catch (Exception e) { fail("instanceof checks", e); }

        // в”Ђв”Ђ runParade в”Ђв”Ђ
        try {
            PixarCharacter[] cast = {
                new Toy("Woody", "Toy Story", "Andy"),
                new Monster("Sulley", "Monsters Inc", 10),
                new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength")
            };
            String result = ParadeUtils.runParade(cast);
            // Check the summary line is present and correct
            boolean hasSummary = result.contains("Parade: 1 toys, 1 monsters, 1 supers");
            check("runParade() summary line",
                  "true", String.valueOf(hasSummary));
        } catch (Exception e) { fail("runParade() summary", e); }

        try {
            PixarCharacter[] cast = {
                new Toy("Woody", "Toy Story", "Andy"),
                new Toy("Buzz", "Toy Story", "Andy"),
                new Monster("Sulley", "Monsters Inc", 10),
                new Monster("Mike", "Monsters Inc", 6),
                new SuperPixar("Mr. Incredible", "The Incredibles", "Super strength"),
                new SuperPixar("Elastigirl", "The Incredibles", "Elasticity")
            };
            String result = ParadeUtils.runParade(cast);
            boolean hasSummary = result.contains("Parade: 2 toys, 2 monsters, 2 supers");
            check("runParade() summary вЂ” 2 of each",
                  "true", String.valueOf(hasSummary));
        } catch (Exception e) { fail("runParade() summary вЂ” 2 of each", e); }

        try {
            PixarCharacter[] cast = {
                new Toy("Woody", "Toy Story", "Andy"),
                new Monster("Sulley", "Monsters Inc", 10)
            };
            String result = ParadeUtils.runParade(cast);
            // Check that toString() and perform() output appear
            boolean hasToString = result.contains("Toy: Woody (Toy Story)");
            boolean hasPerform  = result.contains("Woody comes to life and plays!");
            check("runParade() includes toString & perform output",
                  "true", String.valueOf(hasToString && hasPerform));
        } catch (Exception e) { fail("runParade() toString & perform", e); }

        // в”Ђв”Ђ Encapsulation spot-checks в”Ђв”Ђ
        try {
            java.lang.reflect.Field f = Toy.class.getDeclaredField("owner");
            check("Toy.owner is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Toy.owner field exists", new Exception("Field 'owner' not found"));
        } catch (Exception e) { fail("Toy.owner is private", e); }

        try {
            java.lang.reflect.Field f = Monster.class.getDeclaredField("scarePower");
            check("Monster.scarePower is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Monster.scarePower field exists", new Exception("Field 'scarePower' not found"));
        } catch (Exception e) { fail("Monster.scarePower is private", e); }
    }

    // в”Ђв”Ђ Helpers в”Ђв”Ђ
    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " вЂ” expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " вЂ” " + e.getMessage()); failed++;
    }
}
